// This Java program implements the merge sort algorithm to sort an array of non-negative integers in ascending order.
// It includes error handling for unexpected inputs and outputs the sorted array to the console.
// Note: This implementation assumes that the input array contains only non-negative integers.

public class MergeSortExample {

    public static void main(String[] args) {
        int[] data = {4, 1, 3, 2, 5, 8, 6, 7, 0, 9}; // Example array

        try {
            int[] sortedData = mergeSort(data);
            System.out.println("Sorted array: ");
            for (int value : sortedData) {
                System.out.print(value + " ");
            }
        } catch (IllegalArgumentException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }

    // Merge sort function
    public static int[] mergeSort(int[] array) {
        if (array == null || array.length == 0) {
            throw new IllegalArgumentException("Array must not be null or empty");
        }

        if (array.length == 1) {
            return array; // Base case
        }

        int mid = array.length / 2;
        int[] left = new int[mid];
        int[] right = new int[array.length - mid];

        System.arraycopy(array, 0, left, 0, mid);
        System.arraycopy(array, mid, right, 0, array.length - mid);

        left = mergeSort(left); // Sort left half
        right = mergeSort(right); // Sort right half

        return merge(left, right); // Merge the sorted halves
    }

    // Merge function to combine two sorted arrays
    private static int[] merge(int[] left, int[] right) {
        int[] result = new int[left.length + right.length];
        int i = 0, j = 0, k = 0;

        while (i < left.length && j < right.length) {
            if (left[i] < right[j]) {
                result[k++] = left[i++];
            } else {
                result[k++] = right[j++];
            }
        }

        // Append remaining elements
        while (i < left.length) {
            result[k++] = left[i++];
        }

        while (j < right.length) {
            result[k++] = right[j++];
        }

        return result;
    }
